import React, { useState } from 'react';
import axios from 'axios';

function Registration() {
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    serviceType: 'Web Development',
    projectDetails: '',
    paymentMethod: 'Cash' // Standardmäßig auf Cash gesetzt
  });

  const [message, setMessage] = useState('');

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // Wenn Online gewählt wurde, simulieren wir einen Zahlungsvorgang
      if (formData.paymentMethod === 'Online') {
        alert("Redirecting to Secure Online Payment Gateway...");
        // Hier könnte später eine echte API wie Stripe oder Razorpay stehen
      }

      const response = await axios.post('http://localhost:5000/api/hire', formData);
      
      if (response.status === 201) {
        setMessage("✅ Success! Your request and payment preference have been saved.");
        setFormData({ 
          fullName: '', 
          email: '', 
          serviceType: 'Web Development', 
          projectDetails: '', 
          paymentMethod: 'Cash' 
        });
      }
    } catch (error) {
      console.error("Error saving data:", error);
      setMessage("❌ Error! Could not connect to the server.");
    }
  };

  return (
    <div className="container py-5">
      <div className="row justify-content-center">
        <div className="col-md-6 col-lg-5">
          <div className="card shadow-lg border-0 rounded-4 p-4">
            <h2 className="text-center fw-bold mb-4 text-primary">Hire Me</h2>
            
            {message && (
              <div className={`alert ${message.includes('Success') ? 'alert-success' : 'alert-danger'} text-center`}>
                {message}
              </div>
            )}

            <form onSubmit={handleSubmit}>
              {/* Full Name */}
              <div className="mb-3">
                <label className="form-label fw-bold">Full Name</label>
                <input type="text" name="fullName" className="form-control" value={formData.fullName} onChange={handleChange} required />
              </div>

              {/* Email */}
              <div className="mb-3">
                <label className="form-label fw-bold">Email Address</label>
                <input type="email" name="email" className="form-control" value={formData.email} onChange={handleChange} required />
              </div>

              {/* Service Type */}
              <div className="mb-3">
                <label className="form-label fw-bold">Select Service</label>
                <select name="serviceType" className="form-select" value={formData.serviceType} onChange={handleChange}>
                  <option value="Web Development">Web Development</option>
                  <option value="UI/UX Design">UI/UX Design</option>
                  <option value="Assignment Support">Assignment Support</option>
                  <option value="Report Writing">Report Writing</option>
                </select>
              </div>

              {/* Payment Method (NEU) */}
              <div className="mb-3">
                <label className="form-label fw-bold text-danger">Payment Method</label>
                <select name="paymentMethod" className="form-select border-danger" value={formData.paymentMethod} onChange={handleChange}>
                  <option value="Cash">Cash / Direct Pay (After Work)</option>
                  <option value="Online">Online Payment (UPI / Card)</option>
                </select>
                <small className="text-muted">Note: Online payment is simulated for project demo.</small>
              </div>

              {/* Project Details */}
              <div className="mb-4">
                <label className="form-label fw-bold">Project Details</label>
                <textarea name="projectDetails" className="form-control" rows="4" value={formData.projectDetails} onChange={handleChange} required></textarea>
              </div>

              <button type="submit" className="btn btn-primary w-100 fw-bold py-2 shadow">
                Send Request & Continue
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Registration;
